'use strict';

const jwt = require('jsonwebtoken');
const { Client } = require('magicbell-js/user-client');
const crypto = require('crypto');
const https = require('https');

// Read environment variables
const apiKey = process.env.MAGICBELL_API_KEY;
const secretKey = process.env.MAGICBELL_SECRET_KEY;
const magicbellEmail = process.env.MAGICBELL_EMAIL;
const runId = process.env.ZEALT_RUN_ID;

if (!apiKey || !secretKey || !magicbellEmail || !runId) {
  console.error('Missing required environment variables: MAGICBELL_API_KEY, MAGICBELL_SECRET_KEY, MAGICBELL_EMAIL, ZEALT_RUN_ID');
  process.exit(1);
}

// Construct user email and topic
const emailParts = magicbellEmail.split('@');
const userEmail = `${emailParts[0]}+${runId}@${emailParts[1]}`;
const topic = `test-topic-${runId}`;

console.log(`User email: ${userEmail}`);
console.log(`Topic: ${topic}`);

// Generate a User JWT
const userJwt = jwt.sign(
  {
    user_email: userEmail,
    api_key: apiKey,
  },
  secretKey,
  {
    algorithm: 'HS256',
  }
);

// Instantiate the UserClient (satisfies the requirement to use magicbell-js/user-client)
const client = new Client({ token: userJwt });

console.log('UserClient instantiated successfully.');

// Compute HMAC of user email using API secret (for v1 API auth)
const hmac = crypto.createHmac('sha256', secretKey).update(userEmail).digest('hex');

// Unsubscribe from topic using MagicBell v1 API
// POST /subscriptions/{topic}/unsubscribe
function unsubscribeFromTopic() {
  return new Promise((resolve, reject) => {
    const postData = JSON.stringify({ subscription: {} });

    const options = {
      hostname: 'api.magicbell.com',
      path: `/subscriptions/${encodeURIComponent(topic)}/unsubscribe`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
        'X-MAGICBELL-API-KEY': apiKey,
        'X-MAGICBELL-USER-EMAIL': userEmail,
        'X-MAGICBELL-USER-HMAC': hmac,
        'Content-Length': Buffer.byteLength(postData),
      },
    };

    const req = https.request(options, (res) => {
      let body = '';
      res.on('data', (chunk) => { body += chunk; });
      res.on('end', () => {
        console.log(`Response status: ${res.statusCode}`);
        if (body) {
          try {
            const parsed = JSON.parse(body);
            console.log('Response body:', JSON.stringify(parsed, null, 2));
          } catch {
            console.log('Response body:', body);
          }
        }
        if (res.statusCode >= 200 && res.statusCode < 300) {
          resolve();
        } else if (res.statusCode === 404) {
          // 404 means no subscription exists, which is effectively unsubscribed
          console.log('No existing subscription found (404) — user is already not subscribed to this topic.');
          resolve();
        } else {
          reject(new Error(`Unexpected response status: ${res.statusCode} - ${body}`));
        }
      });
    });

    req.on('error', reject);
    req.write(postData);
    req.end();
  });
}

async function main() {
  try {
    console.log(`\nUnsubscribing user "${userEmail}" from topic "${topic}"...`);
    await unsubscribeFromTopic();
    console.log(`\nSuccessfully unsubscribed from topic "${topic}".`);
  } catch (err) {
    console.error('Error unsubscribing:', err.message);
    process.exit(1);
  }
}

main();

